    <script>
        var loadFile = function (event) {
            var reader = new FileReader();
            reader.onload = function () {
                var myImg = document.getElementById('myImg');
                myImg.src = reader.result;
            }
            reader.readAsDataURL(event.target.files[0]);
        }
    </script>

    <script>
        $(document).ready(function () {
            var selectedMedicines = [];

            // إضافة دواء إلى القائمة المختارة
            $('.add-medicine').click(function () {
                var row = $(this).closest('tr');
                var medicineId = parseInt(row.find('.stock').data('medicine-id'));
                var medicineName = row.find('td:first').text();
                var stock = parseInt(row.find('.stock').val());

                if (stock > 0) {
                    // البحث إذا كان الدواء مضاف مسبقاً
                    var existingIndex = selectedMedicines.findIndex(m => m.MedicineId === medicineId);

       ");
                WriteLiteral(@"             if (existingIndex >= 0) {
                        // تحديث الكمية إذا كان الدواء موجود
                        selectedMedicines[existingIndex].Stock = stock;
                    } else {
                        // إضافة دواء جديد
                        selectedMedicines.push({
                            MedicineId: medicineId,
                            Stock: stock,
                            Name: medicineName
                        });
                    }

                    updateSelectedList();
                    updateHiddenField();
                } else {
                    alert('الكمية يجب أن تكون أكبر من الصفر');
                }
            });

            // تحديث قائمة الأدوية المختارة
            function updateSelectedList() {
                var list = $('#selectedList');
                list.empty();

                if (selectedMedicines.length === 0) {
                    list.append('<tr class=""empty-row""><td colspan""3"" class=""text-center");
                WriteLiteral(@" text-muted"">لا توجد أدوية مختارة</td></tr>');
                } else {
                    selectedMedicines.forEach(function (medicine, index) {
                        list.append(`
                                  <tr style=""background-color: darkgray;"">
                                        <td>${medicine.Name}</td>
                                        <td class=""text-center"">${medicine.Stock}</td>
                                        <td class=""text-center"">
                                            <button type=""button"" class=""btn btn-sm btn-danger remove-medicine"" data-medicine-id=""${medicine.MedicineId}"">
                                                <i class=""fas fa-trash""></i>
                                            </button>
                                        </td>
                                  </tr>

                            `);
                    });
                }
            }


            // ضبط ارتفاع الحاوية تلقائيا
            function");
                WriteLiteral(@" adjustContainerHeight() {
                const container = $('#selectedMedicinesContainer');
                const itemCount = selectedMedicines.length;

                if (itemCount === 0) {
                    container.css('max-height', '200px');
                } else if (itemCount <= 3) {
                    container.css('max-height', (itemCount * 60 + 20) + 'px');
                } else {
                    container.css('max-height', '200px'); // حد اقصى مع اظهار scroll
                }
            }

            // حذف دواء من القائمة المختارة
            $(document).on('click', '.remove-medicine', function () {
                var medicineId = parseInt($(this).data('medicine-id'));
                selectedMedicines = selectedMedicines.filter(m => m.MedicineId !== medicineId);
                updateSelectedList();
                updateHiddenField();
                adjustContainerHeight();
            });

            // تحديث الحقل المخفي بالأدوية المختارة
            fu");
                WriteLiteral(@"nction updateHiddenField() {
                var medicinesToSend = selectedMedicines.map(m => ({
                    MedicineId: m.MedicineId,
                    Stock: m.Stock
                }));
                $('#medicinesJson').val(JSON.stringify(medicinesToSend));
            }

            // التأكد من اختيار دواء واحد على الأقل
            $('#pharmacyForm').submit(function (e) {
                if (selectedMedicines.length === 0) {
                    e.preventDefault();
                    alert('يجب اختيار دواء واحد على الأقل');
                }
            });
        });
    </script>
");
